        heads_cfg: Dict[str, Dict[str, Any]],
        hidden_channels: int = 32,
    ):
        super().__init__()
        self.base_model = base_model
        self.pred_channels = pred_channels
        self.heads_cfg = heads_cfg
        self.hidden_channels = hidden_channels
