from __future__ import annotations

from typing import Any, Dict, Optional, Tuple

import torch
import torch.nn as nn
import torch.nn.functional as F


def _extract_pred_and_extras(
    prediction: Any,
    target: Optional[torch.Tensor] = None,
    batch: Optional[Dict[str, Any]] = None,
) -> Tuple[torch.Tensor, Dict[str, Any], Optional[torch.Tensor], Dict[str, Any]]:
    extras: Dict[str, Any] = {}
    meta: Dict[str, Any] = {}
    pred = prediction

    if isinstance(prediction, dict):
        pred = prediction.get("pred", prediction.get("prediction", prediction.get("output")))
        if pred is None:
            raise KeyError("Expected prediction dict to include one of: pred, prediction, output")
        raw_extras = prediction.get("loss_inputs", {}) or {}
        if not isinstance(raw_extras, dict):
            raise TypeError("prediction['loss_inputs'] must be a dict when provided")
        extras.update(raw_extras)
        if target is None:
            target = prediction.get("target")
        meta = {k: v for k, v in prediction.items() if k not in {"pred", "prediction", "output", "loss_inputs", "target"}}
    elif isinstance(prediction, (tuple, list)):
        if len(prediction) == 0:
            raise ValueError("Prediction tuple/list cannot be empty")
        pred = prediction[0]
        if len(prediction) > 1 and prediction[1] is not None:
            if not isinstance(prediction[1], dict):
                raise TypeError("Second element of prediction tuple/list must be a dict or None")
            extras.update(prediction[1])
        if len(prediction) > 2 and target is None and torch.is_tensor(prediction[2]):
            target = prediction[2]

    if batch:
        if target is None:
            for key in ("target", "hr", "gt", "label", "y"):
                value = batch.get(key)
                if torch.is_tensor(value):
                    target = value
                    break
        batch_extras = batch.get("loss_inputs")
        if isinstance(batch_extras, dict):
            merged = dict(batch_extras)
            merged.update(extras)
            extras = merged

    if not torch.is_tensor(pred):
        raise TypeError(f"Prediction must resolve to a tensor, got {type(pred)}")
    if target is not None and not torch.is_tensor(target):
        raise TypeError(f"Target must be a tensor when provided, got {type(target)}")

    return pred, extras, target, meta


def _to_nchw(x: torch.Tensor) -> torch.Tensor:
    if x.ndim != 4:
        raise ValueError(f"Expected 4D tensor, got shape {tuple(x.shape)}")
    if x.shape[1] <= 8 and x.shape[-1] > 8:
        return x.contiguous()
    return x.permute(0, 3, 1, 2).contiguous()


def _to_nhwc(x: torch.Tensor, like: torch.Tensor) -> torch.Tensor:
    if like.ndim != 4:
        return x
    if like.shape[1] <= 8 and like.shape[-1] > 8:
        return x
    return x.permute(0, 2, 3, 1).contiguous()


def _prepare_mol_params(pred: torch.Tensor, extras: Dict[str, Any], num_mix: int) -> Tuple[torch.Tensor, torch.Tensor, torch.Tensor]:
    mean = extras.get("mol_mean")
    log_scale = extras.get("mol_log_scale")
    logits = extras.get("mol_logits")

    pred_nchw = _to_nchw(pred)
    batch_size, channels, height, width = pred_nchw.shape

    if mean is None:
        mean = pred_nchw.unsqueeze(2).repeat(1, 1, num_mix, 1, 1)
    else:
        mean = _to_nchw(mean)
        if mean.shape[1] == channels * num_mix:
            mean = mean.view(batch_size, channels, num_mix, height, width)
        elif mean.ndim != 5:
            raise ValueError("mol_mean must be [B, C*K, H, W] or [B, C, K, H, W]")

    if log_scale is None:
        log_scale = pred_nchw.new_full((batch_size, channels, num_mix, height, width), -1.0)
    else:
        log_scale = _to_nchw(log_scale)
        if log_scale.shape[1] == channels * num_mix:
            log_scale = log_scale.view(batch_size, channels, num_mix, height, width)
        elif log_scale.ndim != 5:
            raise ValueError("mol_log_scale must be [B, C*K, H, W] or [B, C, K, H, W]")

    if logits is None:
        logits = pred_nchw.new_zeros((batch_size, channels, num_mix, height, width))
    else:
        logits = _to_nchw(logits)
        if logits.shape[1] == channels * num_mix:
            logits = logits.view(batch_size, channels, num_mix, height, width)
        elif logits.ndim != 5:
            raise ValueError("mol_logits must be [B, C*K, H, W] or [B, C, K, H, W]")

    return mean, log_scale.clamp(min=-7.0, max=7.0), logits


def _mixture_logistic_nll(
    target: torch.Tensor,
    mean: torch.Tensor,
    log_scale: torch.Tensor,
    logits: torch.Tensor,
    bin_size: float,
    eps: float,
) -> torch.Tensor:
    target_nchw = _to_nchw(target).unsqueeze(2)
    centered = target_nchw - mean
    inv_scale = torch.exp(-log_scale)

    plus_in = (centered + 0.5 * bin_size) * inv_scale
    minus_in = (centered - 0.5 * bin_size) * inv_scale

    cdf_plus = torch.sigmoid(plus_in)
    cdf_minus = torch.sigmoid(minus_in)
    log_cdf_delta = torch.log((cdf_plus - cdf_minus).clamp_min(eps))
    log_mix = F.log_softmax(logits, dim=2)
    log_prob = torch.logsumexp(log_mix + log_cdf_delta, dim=2)
    return -log_prob.mean()


class Loss(nn.Module):
    def __init__(self, config: Optional[Dict[str, Any]] = None):
        super().__init__()
        config = config or {}
        self.l1_weight = float(config.get("l1_weight", 1.0))
        self.mol_weight = float(config.get("mol_weight", 1.0))
        self.num_mix = int(config.get("num_mix", 5))
        self.bin_size = float(config.get("bin_size", 1.0 / 255.0))
        self.eps = float(config.get("eps", 1e-8))
        self.last_metrics: Dict[str, float] = {}

    def forward(
        self,
        prediction: Any,
        target: Optional[torch.Tensor] = None,
        batch: Optional[Dict[str, Any]] = None,
        **_: Any,
    ) -> torch.Tensor:
        pred, extras, resolved_target, _meta = _extract_pred_and_extras(prediction, target=target, batch=batch)
        if resolved_target is None:
            raise ValueError("Loss requires target tensor via target argument, batch, or prediction dict")

        l1 = F.l1_loss(pred, resolved_target)
        mean, log_scale, logits = _prepare_mol_params(pred, extras, self.num_mix)
        mol = _mixture_logistic_nll(
            target=resolved_target,
            mean=mean,
            log_scale=log_scale,
            logits=logits,
            bin_size=self.bin_size,
            eps=self.eps,
        )
        total = self.l1_weight * l1 + self.mol_weight * mol
        self.last_metrics = {
            "loss_total": float(total.detach().cpu()),
            "loss_l1": float(l1.detach().cpu()),
            "loss_mol": float(mol.detach().cpu()),
        }
        return total


class CandidateLoss(Loss):
    pass

